// ─── CONTACT PAGE ─────────────────────────────────────────────────────────────
// Contact form data is stored in DB and shown in Admin → Contact Queries page
export const Contact = () => {
  const [sent, setSent]     = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [form, setForm]     = useState({ name: "", email: "", phone: "", subject: "", message: "" });

  const f = k => e => setForm(p => ({ ...p, [k]: e.target.value }));

  const validate = () => {
    const e = {};
    if (!form.name.trim())                   e.name    = "Name is required";
    if (!form.email.trim())                  e.email   = "Email is required";
    else if (!form.email.includes("@"))      e.email   = "Enter a valid email address";
    if (!form.phone.trim())                  e.phone   = "Phone number is required";
    else if (form.phone.replace(/\D/g,"").length < 10) e.phone = "Enter a valid phone number";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSend = async () => {
    if (!validate()) return;
    try {
      setLoading(true);
      await submitContactMessage(form);
      setSent(true);
    } catch (err) {
      alert("Failed to send message: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = (field) => ({
    width: "100%", background: T.bg3,
    border: `1.5px solid ${errors[field] ? "#ef4444" : T.border}`,
    borderRadius: 9, padding: "10px 14px", fontSize: 13,
    color: T.text, outline: "none", fontFamily: "DM Sans",
    boxSizing: "border-box",
  });

  const errTxt = (field) => errors[field]
    ? <div style={{ fontSize: 11, color: "#ef4444", marginTop: 4 }}>⚠ {errors[field]}</div>
    : null;

  return (
    <div style={{ padding: "60px 60px 80px", maxWidth: 1100, margin: "0 auto" }}>
      <div style={{ textAlign: "center", marginBottom: 52 }}>
        <Badge type="info">Contact</Badge>
        <h2 style={{ fontFamily: "Syne", fontSize: 38, fontWeight: 800, margin: "12px 0" }}>Get In Touch</h2>
        <p style={{ fontSize: 15, color: T.muted }}>We're here to help. Messages are stored and reviewed by our admin team.</p>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1.4fr", gap: 36 }}>
        <div>
          {[
            { icon: "📍", label: "Address", val: "Zenelait InfoTech, Anna Salai, Chennai, Tamil Nadu - 600002" },
            { icon: "📞", label: "Phone",   val: "+91 98765 43210" },
            { icon: "✉️", label: "Email",   val: "info@zenelaitinfotech.com" },
            { icon: "🕐", label: "Office Hours", val: "Mon–Sat: 9:00 AM – 6:00 PM" },
          ].map(c => (
            <div key={c.label} style={{ display: "flex", gap: 16, marginBottom: 24 }}>
              <div style={{ width: 44, height: 44, background: `${T.primary}18`, borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, flexShrink: 0 }}>{c.icon}</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 2 }}>{c.label}</div>
                <div style={{ fontSize: 13, color: T.muted }}>{c.val}</div>
              </div>
            </div>
          ))}
        </div>
        <Card style={{ padding: 28 }}>
          <h3 style={{ fontFamily: "Syne", fontSize: 20, fontWeight: 800, marginBottom: 20 }}>Send a Message</h3>
          {!sent ? (
            <>
              {/* Name * */}
              <div style={{ marginBottom: 14 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: errors.name ? "#ef4444" : T.muted, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 6 }}>
                  Your Name <span style={{ color: "#ef4444" }}>*</span>
                </label>
                <input value={form.name} onChange={f("name")} placeholder="Enter your full name" style={inputStyle("name")} />
                {errTxt("name")}
              </div>

              {/* Email * */}
              <div style={{ marginBottom: 14 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: errors.email ? "#ef4444" : T.muted, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 6 }}>
                  Email Address <span style={{ color: "#ef4444" }}>*</span>
                </label>
                <input type="email" value={form.email} onChange={f("email")} placeholder="your@email.com" style={inputStyle("email")} />
                {errTxt("email")}
              </div>

              {/* Phone * */}
              <div style={{ marginBottom: 14 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: errors.phone ? "#ef4444" : T.muted, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 6 }}>
                  Phone Number <span style={{ color: "#ef4444" }}>*</span>
                </label>
                <input value={form.phone} onChange={f("phone")} placeholder="+91 98765 43210" style={inputStyle("phone")} />
                {errTxt("phone")}
              </div>

              {/* Subject */}
              <div style={{ marginBottom: 14 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 6 }}>Subject</label>
                <input value={form.subject} onChange={f("subject")} placeholder="What is this regarding?" style={inputStyle("subject")} />
              </div>

              {/* Message */}
              <div style={{ marginBottom: 16 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 6 }}>Message</label>
                <textarea rows={4} value={form.message} onChange={f("message")} placeholder="Write your message here..."
                  style={{ ...inputStyle("message"), resize: "vertical" }} />
              </div>

              <Btn variant="primary" size="lg" full onClick={handleSend} disabled={loading}>
                {loading ? "Sending..." : "Send Message →"}
              </Btn>
            </>
          ) : (
            <div style={{ textAlign: "center", padding: "32px 0" }}>
              <div style={{ fontSize: 52 }}>✅</div>
              <h3 style={{ fontFamily: "Syne", fontSize: 20, fontWeight: 800, marginTop: 16 }}>Message Sent!</h3>
              <p style={{ color: T.muted, fontSize: 14, marginTop: 8 }}>Your query has been stored. Our admin team will respond within 24 hours.</p>
              <Btn variant="ghost" size="sm" onClick={() => { setSent(false); setForm({ name: "", email: "", phone: "", subject: "", message: "" }); }} style={{ marginTop: 16 }}>
                Send Another
              </Btn>
            </div>
          )}
        </Card>
      </div>
    </div>
  );
};

